/**
 * Generate Manus firewall config.
 *
 * Data source: https://open.manus.im/docs/api-reference/create-task
 *
 * Manus uses API key authentication via x-manus-api-key header.
 * Token format: sk_ + ~72 alphanumeric chars.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://open.manus.im/docs/api-reference/create-task";
// Format: sk_ + ~72 alphanumeric chars
const PLACEHOLDER_VALUE =
  "sk_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeL";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Manus API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:manus",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const manusFirewall = {",
    '  name: "manus",',
    '  description: "Manus",',
    "  placeholders: {",
    `    MANUS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.manus.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-manus-api-key": "${{ secrets.MANUS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Manus firewall config...");
  const ts = generateTypeScript();
  writeOutput("manus", ts, import.meta.dirname);
}
